1	import path from "node:path";
2	import { createBashTool, bashTool } from "@mariozechner/pi-coding-agent";
3	import type { AgentTool } from "@mariozechner/pi-agent-core";
4	import { wechatbotAgentWorkspace } from "../../lib/wechatbot-workspace";
5	
6	export type SchoolIdentityContext = {
7	  role: "student" | "teacher";
8	  schoolId: string;
9	} | null;
10	
11	const PROJECT_ROOT = path.resolve(process.cwd());
12	
13	/** 所有用户数据目录的公共父目录，用于检测跨用户访问 */
14	const WECHATBOT_DATA_ROOT = path.resolve(PROJECT_ROOT, ".data", "wechatbot");
15	
16	/** Skills 只读目录 */
17	export const PI_SKILLS_ROOT = path.resolve(PROJECT_ROOT, ".pi", "skills");
18	
19	/** 绝对封锁的系统路径前缀 */
20	const BLOCKED_PREFIXES = [
21	  "/etc",
22	  "/root",
23	  "/sys",
24	  "/proc",
25	  "/dev",
26	  "/boot",
27	  "/private/etc", // macOS
28	];
29	
30	const DEFAULT_SCHOOL_SERVER_URL = "http://127.0.0.1:3002";
31	
32	function escapeRegExp(input: string): string {
33	  return input.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
34	}
35	
36	function schoolServerBaseUrls(): string[] {
37	  const envBase = process.env.SCHOOL_SERVER_URL?.trim();
38	  return [envBase, DEFAULT_SCHOOL_SERVER_URL]
39	    .filter((v): v is string => Boolean(v))
40	    .map((v) => v.replace(/\/$/, ""));
41	}
42	
43	function commandTargetsSchoolServer(command: string): boolean {
44	  const bases = schoolServerBaseUrls();
45	  if (bases.some((base) => command.includes(base))) return true;
46	  return /\/api\/(students|teachers|courses|assignments|library|cafeteria|bus|campus-card|repair)\b/.test(command);
47	}
48	
49	function extractSchoolApiPaths(command: string): string[] {
50	  const matches = command.match(/\/api\/[A-Za-z0-9_./?=&%-]*/g) ?? [];
51	  return matches.map((m) => m.split("?")[0].replace(/[)"'`;,]+$/g, ""));
52	}
53	
54	/** 所有已登录用户均可访问的公共校园信息接口（不含个人数据） */
55	const PUBLIC_API_PATTERNS = [
56	  /^\/api\/library\/seats(\/availability)?$/,
57	  /^\/api\/library\/books(\/[^/]+)?$/,
58	  /^\/api\/cafeteria(\/[^/]+\/menu)?$/,
59	  /^\/api\/cafeteria\/menu\/today$/,
60	  /^\/api\/bus\/routes(\/[^/]+)?$/,
61	  /^\/api\/health$/,
62	];
63	
64	function isAllowedSchoolApiPath(
65	  apiPath: string,
66	  identity: Exclude<SchoolIdentityContext, null>,
67	): boolean {
68	  // 公共接口：任何已绑定身份的用户均可访问
69	  if (PUBLIC_API_PATTERNS.some((p) => p.test(apiPath))) return true;
70	
71	  const id = escapeRegExp(identity.schoolId);
72	
73	  if (identity.role === "student") {
74	    return [
75	      // 教务
76	      new RegExp(`^/api/students/${id}$`),
77	      new RegExp(`^/api/students/${id}/courses$`),
78	      new RegExp(`^/api/assignments/unsubmitted/${id}$`),
79	      new RegExp(`^/api/assignments/student-submissions/${id}$`),
80	      // 图书馆预约（GET 按 studentId，POST/DELETE 服务端校验 body 中的 student_id）
81	      new RegExp(`^/api/library/reservations/${id}$`),
82	      /^\/api\/library\/reservations(\/[^/]+)?$/,
83	      // 校园卡（仅自己）
84	      new RegExp(`^/api/campus-card/${id}$`),
85	      // 报修（GET 按 studentId，POST 新增，PATCH 状态由服务端校验）
86	      new RegExp(`^/api/repair/${id}$`),
87	      /^\/api\/repair(\/[^/]+\/status)?$/,
88	    ].some((pattern) => pattern.test(apiPath));
89	  }
90	
91	  return [
92	    new RegExp(`^/api/teachers/${id}$`),
93	    new RegExp(`^/api/courses/by-teacher/${id}$`),
94	  ].some((pattern) => pattern.test(apiPath));
95	}
96	
97	function validateSchoolApiAccess(
98	  command: string,
99	  identity: SchoolIdentityContext,
100	): void {
101	  if (!commandTargetsSchoolServer(command)) return;
102	  const apiPaths = extractSchoolApiPaths(command);
103	  if (apiPaths.length === 0) return;
104	
105	  if (!identity) {
106	    throw new Error("当前账号未绑定 student/teacher 身份，禁止访问 school-server /api。");
107	  }
108	
109	  for (const apiPath of apiPaths) {
110	    if (!isAllowedSchoolApiPath(apiPath, identity)) {
111	      throw new Error(
112	        `越权教务查询已拦截：${apiPath}。当前绑定 ${identity.role}:${identity.schoolId}，仅允许访问本身份对应接口。`,
113	      );
114	    }
115	  }
116	}
117	
118	function isUnder(parent: string, candidate: string): boolean {
119	  const rel = path.relative(parent, candidate);
120	  return !rel.startsWith("..") && !path.isAbsolute(rel);
121	}
122	
123	/**
124	 * 从 shell 命令字符串中提取所有看起来像绝对路径的 token，
125	 * 并对每个路径执行访问策略检查：
126	 *
127	 *   - userRoot（.data/wechatbot/{userId}/）：读写均可
128	 *   - PI_SKILLS_ROOT（.pi/skills）：仅读；若命令含写操作则阻止
129	 *   - 其他路径：
130	 *       - BLOCKED_PREFIXES → 绝对封锁
131	 *       - 属于其他用户目录 → 封锁
132	 *       - 属于项目目录内其他位置 → 封锁
133	 *       - /usr、/bin、/tmp 等系统可执行路径 → 放行（仅作为命令本身）
134	 */
135	function validatePaths(
136	  command: string,
137	  userRoot: string,
138	  schoolIdentity: SchoolIdentityContext,
139	): void {
140	  // 提取绝对路径 token：以 / 开头、由合法路径字符组成
141	  const absPathRegex = /(?:^|[\s"'`|;&><(])(\/([\w.@%+\-]+(?:\/[\w.@%+\-]*)*)\/?)/g;
142	  let match: RegExpExecArray | null;
143	
144	  // 检测是否有写操作（用于 .pi/skills 只读约束）
145	  const hasOutputRedirect = />{1,2}/.test(command);
146	  const hasWriteCommand =
147	    /\b(rm|rmdir|mv|cp|chmod|chown|touch|truncate|dd|tee|install)\b/.test(
148	      command,
149	    );
150	
151	  while ((match = absPathRegex.exec(command)) !== null) {
152	    const rawPath = match[1];
153	    const resolved = path.resolve(rawPath);
154	
155	    // 系统封锁路径
156	    if (
157	      BLOCKED_PREFIXES.some(
158	        (bp) => resolved === bp || resolved.startsWith(`${bp}/`),
159	      )
160	    ) {
161	      throw new Error(`禁止访问系统路径：${resolved}`);
162	    }
163	
164	    const inUserRoot = isUnder(userRoot, resolved);
165	    const inPiSkills = isUnder(PI_SKILLS_ROOT, resolved);
166	
167	    if (inUserRoot) continue; // 当前用户目录，完全放行
168	
169	    if (inPiSkills) {
170	      // .pi/skills 只读：有写操作时阻止
171	      if (hasOutputRedirect || hasWriteCommand) {
172	        throw new Error(
173	          `.pi/skills 为只读目录，禁止写入操作（路径：${resolved}）`,
174	        );
175	      }
176	      continue;
177	    }
178	
179	    // 其他用户的数据目录：封锁
180	    if (isUnder(WECHATBOT_DATA_ROOT, resolved)) {
181	      throw new Error(`禁止访问其他用户目录：${resolved}`);
182	    }
183	
184	    // 项目目录内的其他路径：封锁
185	    if (isUnder(PROJECT_ROOT, resolved)) {
186	      throw new Error(
187	        `禁止访问项目路径 ${resolved}（仅允许 .data/wechatbot/<用户ID>/ 和 .pi/skills/）`,
188	      );
189	    }
190	
191	    // /usr/bin、/tmp 等系统工具路径：放行（agent 执行命令本身需要）
192	  }
193	
194	  validateSchoolApiAccess(command, schoolIdentity);
195	}
196	
197	/**
198	 * 为特定 wechat 用户创建路径受限的 bash 工具。
199	 *
200	 * 规则：
201	 *   - cwd 固定为 .data/wechatbot/{userId}/
202	 *   - .data/wechatbot/{userId}/ 读写均可（相对路径天然安全）
203	 *   - .pi/skills/ 可读，不可写（skill 脚本通过 $PI_SKILLS_ROOT 访问）
