1	import { constants } from "node:fs";
2	import { access as fsAccess, open as fsOpen, readFile as fsReadFile } from "node:fs/promises";
3	import path from "node:path";
4	import { fileTypeFromBuffer } from "file-type";
5	import { createReadTool } from "@mariozechner/pi-coding-agent";
6	import { wechatbotAgentWorkspace } from "@/lib/wechatbot-workspace";
