8	/** 项目级 skills 只读目录。 */
9	export const PI_SKILLS_ROOT = path.resolve(process.cwd(), ".pi", "skills");
10	
11	const SUPPORTED_IMAGE_MIMES = new Set([
12	  "image/jpeg",
13	  "image/png",
14	  "image/gif",
15	  "image/webp",
16	]);
17	const IMAGE_SNIFF_BYTES = 4100;
18	
19	/**
20	 * 确保绝对路径在 userRoot 之下，防止路径逃逸。
21	 * 被 read-tool 和 wechat-media-tools 共用。
22	 */
23	export function assertPathUnderUserRoot(
24	  userRootResolved: string,
25	  absolutePath: string,
26	): void {
27	  const resolved = path.resolve(absolutePath);
28	  const rel = path.relative(userRootResolved, resolved);
29	  if (rel.startsWith("..") || path.isAbsolute(rel)) {
30	    throw new Error("仅允许访问当前用户目录 .data/wechatbot/<用户ID>/ 下的文件");
31	  }
32	}
33	
34	/**
35	 * 当 agent 传入形如 `.pi/skills/...` 的相对路径时，
36	 * createReadTool 会将其解析为 `{userRoot}/.pi/skills/...`（不存在）。
37	 * 此函数将其重映射到真实的 `PROJECT_ROOT/.pi/skills/...`。
38	 */
39	function remapSkillsPath(absolutePath: string, userRoot: string): string {
40	  const skillsUnderUser = path.join(userRoot, ".pi", "skills");
41	  if (
42	    absolutePath === skillsUnderUser ||
43	    absolutePath.startsWith(skillsUnderUser + path.sep)
44	  ) {
45	    const rel = path.relative(skillsUnderUser, absolutePath);
46	    return path.join(PI_SKILLS_ROOT, rel);
47	  }
48	  return absolutePath;
49	}
