51	/** 与 pi-coding-agent read 工具一致：仅识别支持的图片 MIME。 */
52	async function detectSupportedImageMimeTypeFromFile(
53	  filePath: string,
54	): Promise<string | null | undefined> {
55	  const fh = await fsOpen(filePath, "r");
56	  try {
57	    const buffer = Buffer.alloc(IMAGE_SNIFF_BYTES);
58	    const { bytesRead } = await fh.read(buffer, 0, IMAGE_SNIFF_BYTES, 0);
59	    if (bytesRead === 0) return null;
60	    const fileType = await fileTypeFromBuffer(buffer.subarray(0, bytesRead));
61	    if (!fileType || !SUPPORTED_IMAGE_MIMES.has(fileType.mime)) return null;
62	    return fileType.mime;
63	  } finally {
64	    await fh.close();
65	  }
66	}
