68	/**
69	 * 为特定 wechat 用户创建路径受限的 read 工具。
70	 *
71	 * - cwd 固定为 .data/wechatbot/{userId}/
72	 * - .pi/skills 下的相对路径自动重映射到项目真实路径（只读）
73	 * - 其他路径若逃逸出 userRoot 则抛错
74	 */
75	export function createUserScopedReadTool(
76	  userId: string,
77	): ReturnType<typeof createReadTool> {
78	  const userRoot = path.resolve(wechatbotAgentWorkspace(userId));
79	  const base = createReadTool(userRoot, {
80	    operations: {
81	      readFile: async (absolutePath) => {
82	        const remapped = remapSkillsPath(absolutePath, userRoot);
83	        if (remapped !== absolutePath) return fsReadFile(remapped);
84	        assertPathUnderUserRoot(userRoot, absolutePath);
85	        return fsReadFile(absolutePath);
86	      },
87	      access: async (absolutePath) => {
88	        const remapped = remapSkillsPath(absolutePath, userRoot);
89	        if (remapped !== absolutePath) return fsAccess(remapped, constants.R_OK);
90	        assertPathUnderUserRoot(userRoot, absolutePath);
91	        return fsAccess(absolutePath, constants.R_OK);
92	      },
93	      detectImageMimeType: async (absolutePath) => {
94	        const remapped = remapSkillsPath(absolutePath, userRoot);
95	        if (remapped !== absolutePath)
96	          return detectSupportedImageMimeTypeFromFile(remapped);
97	        assertPathUnderUserRoot(userRoot, absolutePath);
98	        return detectSupportedImageMimeTypeFromFile(absolutePath);
99	      },
100	    },
101	  });
102	  return {
103	    ...base,
104	    description:
105	      `${base.description} 当前会话 read 的根目录已固定为「本机账号 ${userId}」的 Agent 工作区：${userRoot}。` +
106	      `只传相对路径（如用户消息里的保存文件名）。` +
107	      `不要对 .data/wechatbot 父目录做 read（应先用 list_wechat_user_media 再 read 子目录内文件）。` +
108	      `向外发本地文件用 wechat_send 的 file_path / image_path / video_path。`,
109	  };
110	}
