52	/** 将用户发来的媒体落盘到用户目录，返回相对路径（相对该用户目录）。 */
53	export async function saveUserIncomingMediaFile(
54	  userId: string,
55	  data: Buffer,
56	  hintFileName?: string,
57	): Promise<string> {
58	  const dir = wechatUserMediaRoot(userId);
59	  const base = path.basename(hintFileName || "file") || "file";
60	  const safeBase = base.replace(/[^\w.\-]+/g, "_").slice(0, 120);
61	  const name = `${Date.now()}-${randomBytes(4).toString("hex")}-${safeBase}`;
62	  const abs = path.join(dir, name);
63	  await writeFile(abs, data);
64	  return name;
65	}
