67	function buildSendContentForLocalFile(
68	  buf: Buffer,
69	  fileName: string,
70	  caption?: string,
71	): SendContent {
72	  const base = path.basename(fileName);
73	  const lower = base.toLowerCase();
74	  if (/\.(mp4|mov|webm)$/i.test(lower)) {
75	    return { video: buf, caption };
76	  }
77	  if (/\.(png|jpe?g|gif|webp|bmp)$/i.test(lower)) {
78	    return { image: buf, caption };
79	  }
80	  return { file: buf, fileName: base, caption };
81	}
