89	/**
90	 * 供 pi-agent 调用：微信发送能力（对齐 WeChatBot send / reply 与 SendContent）。
91	 */
92	export function buildWechatMediaTools(
93	  ownerUserId: string,
94	  bot: WeChatBot,
95	  opts?: BuildWechatMediaToolsOpts,
96	): AgentTool[] {
97	  const listWechatUserMedia: AgentTool = {
98	    name: "list_wechat_user_media",
99	    label: "列出当前账号微信媒体目录",
100	    description:
101	      "列出当前微信 Bot 对应 Agent 工作区（.data/wechatbot/<账号用户ID>/）中的文件名（与 read、wechat_send 的本地路径使用同一根目录）。用于在 read 前确认有哪些已落盘文件；若用户消息含「图片已保存…相对路径：xxx」则该文件在此目录下。",
102	    parameters: Type.Object({}),
103	    execute: async () => {
104	      const root = path.resolve(wechatUserMediaRoot(ownerUserId));
105	      const names = await fsReaddir(root);
106	      if (names.length === 0) {
107	        return {
108	          content: [
109	            {
110	              type: "text",
111	              text: `当前账号媒体目录中尚无文件：${root}`,
112	            },
113	          ],
114	          details: { path: root, count: 0 },
115	        };
116	      }
117	      names.sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()));
118	      return {
119	        content: [
120	          {
121	            type: "text",
122	            text: `${names.length} 个条目（${root}）：\n${names.join("\n")}`,
123	          },
124	        ],
125	        details: { path: root, count: names.length },
126	      };
127	    },
128	  };
129	
130	  const wechatSend: AgentTool = {
131	    name: "wechat_send",
132	    label: "微信 send / reply（对齐 SDK）",
133	    description:
134	      "与 WeChatBot.send(userId, content) / reply(msg, content) 一致。须且仅能指定一种内容：" +
135	      "text（纯文本，可直接作为字符串发送）；url（http(s)，微信自动下载并识别类型）；image_path / video_path / file_path（均相对于当前 Bot 工作区 .data/wechatbot/<用户ID>/）。" +
136	      " file_path 按扩展名自动当作图片、视频或附件，等同 SDK 的 { file, fileName }。" +
137	      " caption 可选。file_name 可选：与 file_path 合用时覆盖展示文件名（须含扩展名）；与 url 合用时对应 SDK 的 fileName。" +
138	      " target_user_id：发给「非当前这条入站消息的发送人」时必须填写，此时 bot.send。" +
139	      " 若当前有入站消息且未填 target、或填的 target 与发消息者相同，则 bot.reply(msg, …)（推荐发图/发文件）。" +
140	      " 无入站上下文时回退 defaultWechatTarget 的 send；二者皆无则报错（定时任务等须写 target_user_id）。" +
141	      ` 单文件最大约 ${Math.round(maxBytes() / (1024 * 1024))}MB。`,
142	    parameters: Type.Object({
143	      target_user_id: Type.Optional(
144	        Type.String({
145	          description:
146	            "接收方微信 userId（如 xxx@im.wechat）。省略则 reply 或默认 send，见工具说明",
147	        }),
148	      ),
149	      text: Type.Optional(
150	        Type.String({ description: "纯文本内容；与其它内容字段互斥" }),
151	      ),
152	      url: Type.Optional(
153	        Type.String({
154	          description: "http(s) 资源地址；与 text/路径类互斥",
155	        }),
156	      ),
157	      image_path: Type.Optional(
158	        Type.String({
159	          description:
160	            "媒体目录内相对路径，按图片发送 { image, caption }；与其它内容字段互斥",
161	        }),
162	      ),
163	      video_path: Type.Optional(
164	        Type.String({
165	          description:
166	            "媒体目录内相对路径，按视频发送 { video, caption }；与其它内容字段互斥",
167	        }),
168	      ),
169	      file_path: Type.Optional(
170	        Type.String({
171	          description:
172	            "媒体目录内相对路径，{ file, fileName } 并按扩展名自动路由；与其它内容字段互斥",
173	        }),
174	      ),
175	      file_name: Type.Optional(
176	        Type.String({
177	          description:
178	            "与 file_path 或 url 合用：覆盖 fileName（须含扩展名，影响类型判定）",
179	        }),
180	      ),
181	      caption: Type.Optional(
182	        Type.String({ description: "图片 / 视频 / URL 等可选配文" }),
183	      ),
184	    }),
185	    execute: async (_toolCallId, params) => {
186	      const p = params as Record<string, unknown>;
187	      const caption = String(p.caption ?? "").trim() || undefined;
188	      const textRaw = String(p.text ?? "").trim();
189	      const url = String(p.url ?? "").trim();
190	      const imagePath = String(p.image_path ?? "").trim();
191	      const videoPath = String(p.video_path ?? "").trim();
192	      const filePath = String(p.file_path ?? "").trim();
193	      const fileNameOpt = String(p.file_name ?? "").trim();
194	
195	      const modeCount = [
196	        textRaw,
197	        url,
198	        imagePath,
199	        videoPath,
200	        filePath,
201	      ].filter((s) => s.length > 0).length;
202	      if (modeCount !== 1) {
203	        throw new Error(
204	          "须且仅能指定一种：text、url、image_path、video_path、file_path",
205	        );
206	      }
207	
208	      const limit = maxBytes();
209	      const readBoundedFile = (rel: string, label: string): Buffer => {
210	        const abs = resolvePathUnderUserWechatMediaRoot(ownerUserId, rel);
211	        if (!existsSync(abs)) {
212	          throw new Error(`${label} 不存在：${rel}`);
213	        }
214	        const st = statSync(abs);
215	        if (!st.isFile()) {
216	          throw new Error(`${label} 不是普通文件：${rel}`);
217	        }
218	        if (st.size > limit) {
219	          throw new Error(`文件过大（>${limit} 字节）：${rel}`);
220	        }
221	        return readFileSync(abs);
222	      };
223	
224	      let content: SendContent;
225	      if (textRaw) {
226	        content = textRaw;
227	      } else if (url) {
228	        if (!/^https?:\/\//i.test(url)) {
229	          throw new Error("url 必须以 http:// 或 https:// 开头");
230	        }
231	        content = {
232	          url,
233	          caption,
234	          ...(fileNameOpt ? { fileName: fileNameOpt } : {}),
235	        };
236	      } else if (imagePath) {
237	        const buf = readBoundedFile(imagePath, "image_path");
238	        content = { image: buf, caption };
239	      } else if (videoPath) {
240	        const buf = readBoundedFile(videoPath, "video_path");
241	        content = { video: buf, caption };
242	      } else {
243	        const buf = readBoundedFile(filePath, "file_path");
244	        const displayName = fileNameOpt || path.basename(filePath);
245	        content = buildSendContentForLocalFile(buf, displayName, caption);
246	      }
247	
248	      const explicitTarget = String(p.target_user_id ?? "").trim();
249	      const incoming = opts?.incomingWechatMessage;
250	      let delivery: { kind: "send"; peer: string };
251	
252	      // 确定目标用户ID：优先使用显式指定的target，否则使用入站消息的发送者
253	      const targetUserId = explicitTarget || incoming?.userId;
254	      
255	      if (!targetUserId) {
256	        throw new Error(
257	          "需要 target_user_id；或在微信消息回调中调用；或提供默认接收方",
258	        );
259	      }
260	      
261	      // 统一使用 send 方法，确保 agent 明确知道目标用户ID
262	      await bot.send(targetUserId, content);
263	      delivery = { kind: "send", peer: targetUserId };
264	
265	      return {
266	        content: [
267	          {
268	            type: "text",
269	            text: `已发送微信消息（${delivery.kind} → ${delivery.peer}）。`,
270	          },
271	        ],
272	        details: delivery,
273	      };
274	    },
275	  };
276	
277	  return [listWechatUserMedia, wechatSend];
278	}
