361	  private async notifyCourseStudentsForPublishedAssignment(input: {
362	    courseId: string;
363	    courseName: string;
364	    assignmentTitle: string;
365	    deadlineUnix: number;
366	  }): Promise<{ delivered: number; skipped: number }> {
367	    const students = await schoolApiGet<Array<{ id: string }>>(
368	      `/api/courses/${input.courseId}/students`,
369	    );
370	    if (students.length === 0) return { delivered: 0, skipped: 0 };
371	
372	    const studentIds = students.map((s) => s.id);
373	    const bindings = await db
374	      .select({
375	        userId: userSchoolBindings.userId,
376	      })
377	      .from(userSchoolBindings)
378	      .where(
379	        and(
380	          eq(userSchoolBindings.role, "student"),
381	          inArray(userSchoolBindings.schoolId, studentIds),
382	        ),
383	      );
384	
385	    const studentUserIds = bindings.map((b) => b.userId);
386	    if (studentUserIds.length === 0) return { delivered: 0, skipped: students.length };
387	
388	    const { botService } = await import("@/lib/bot/service");
389	    const deadlineText = new Date(input.deadlineUnix * 1000).toLocaleString();
390	    const text =
391	      `你有新的课程作业：${input.assignmentTitle}\n` +
392	      `课程：${input.courseName}\n` +
393	      `截止：${deadlineText}\n` +
394	      `请及时完成并提交。`;
395	
396	    let delivered = 0;
397	    let skipped = 0;
398	    for (const studentUserId of studentUserIds) {
399	      const peer = this.lastIncomingPeerByOwner.get(studentUserId);
400	      const targetBot = botService.getBot(studentUserId);
401	      if (!peer || !targetBot) {
402	        skipped += 1;
403	        continue;
404	      }
405	      try {
406	        await targetBot.send(peer, text);
407	        delivered += 1;
408	      } catch {
409	        skipped += 1;
410	      }
411	    }
412	    return { delivered, skipped };
413	  }
