88	/** 将无效/被清空的图片块改为纯文本说明，避免上游收到 `data:...base64,` 空载荷 */
89	function sanitizePersistedMessages(messages: AgentMessage[]): AgentMessage[] {
90	  const stripImages = (
91	    blocks: (TextContent | ImageContent)[],
92	    emptyLabel: string,
93	  ): (TextContent | ImageContent)[] =>
94	    blocks.flatMap((block) => {
95	      if (block.type === "image" && !isPlausibleImageBase64(block.data)) {
96	        return [{ type: "text" as const, text: emptyLabel }];
97	      }
98	      return [block];
99	    });
100	
101	  return messages.map((m): AgentMessage => {
102	    if (m.role === "user") {
103	      if (typeof m.content === "string") return m;
104	      return {
105	        ...m,
106	        content: stripImages(
107	          m.content,
108	          "（历史图片未持久化，已省略；若需要请重新发送图片。）",
109	        ),
110	      };
111	    }
112	    if (m.role === "toolResult") {
113	      return {
114	        ...m,
115	        content: stripImages(m.content, "（工具返回中的图片已省略。）"),
116	      };
117	    }
118	    return m;
119	  });
120	}
