296	  private chains = new Map<string, Promise<void>>();
297	  /** 最近一次 prompt 时间（仅内存中有 Session 的用户） */
298	  private lastActivity = new Map<string, number>();
299	  /** 当前内存 Session 与磁盘 jsonl 的增量同步（idle 回收后会清空，下次从最新文件重载） */
300	  private sessionFileState = new Map<string, SessionFileState>();
