308	  /** 在访问 Session 前惰性回收空闲实例（无全局 setInterval） */
309	  private async evictIdleSessionsIfStale(idleMs: number): Promise<void> {
310	    const now = Date.now();
311	    for (const [uid, session] of [...this.sessions.entries()]) {
312	      if (session.isStreaming) continue;
313	      const last = this.lastActivity.get(uid) ?? 0;
314	      if (now - last < idleMs) continue;
315	      try {
316	        await session.abort();
317	      } catch {
318	        /* ignore */
319	      }
320	      try {
321	        session.dispose();
322	      } catch {
323	        /* ignore */
324	      }
325	      this.sessions.delete(uid);
326	      this.lastActivity.delete(uid);
327	      this.sessionFileState.delete(uid);
328	      console.log(
329	        `[agent] 空闲回收 Session user ${uid}（>${Math.round(idleMs / 60_000)}min 无对话）`,
330	      );
331	    }
332	  }
