334	  async getOrCreate(userId: string): Promise<AgentSession> {
335	    const idleMin = agentSessionIdleMinutes();
336	    if (idleMin > 0) {
337	      await this.evictIdleSessionsIfStale(idleMin * 60_000);
338	    }
339	    let s = this.sessions.get(userId);
340	    if (!s) {
341	      const persisted = loadPersistedMessagesFromJsonl(userId);
342	      s = await createUserSession(userId, persisted);
343	      this.sessions.set(userId, s);
344	      const latest = getLatestSessionJsonlPath(userId);
345	      if (latest) {
346	        this.sessionFileState.set(userId, {
347	          path: latest,
348	          messageLinesOnDisk: persisted.length,
349	        });
350	      }
351	    }
352	    return s;
353	  }
